// Comments is the resolver for the comments field.
func (r *queryResolver) Comments(ctx context.Context, bodySlug string, cursor *string, limit *int) (*model.CommentConnection, error) {
	if r.useMock() {
		return mockCommentConnection(bodySlug)
	}

	lim := int32(20)
	if limit != nil {
		lim = int32(*limit)
	}
	offset := int32(0)
	if cursor != nil {
		if _, err := fmt.Sscanf(*cursor, "%d", &offset); err != nil || offset < 0 {
			offset = 0
		}
	}
	if lim < 1 {
		lim = 20
	}
	if lim > 100 {
		lim = 100
	}

	comments, total, err := r.Repos.Comment.ListByBody(ctx, bodySlug, lim, offset)
	if err != nil {
		return nil, fmt.Errorf("list comments: %w", err)
	}

	edges := make([]*model.CommentEdge, len(comments))
	for i, c := range comments {
		gc := repository.CommentToGraphQL(&c)
		gc.BodySlug = bodySlug
		edges[i] = &model.CommentEdge{
			Cursor: fmt.Sprintf("%d", offset+int32(i)),
			Node:   gc,
		}
	}

	var startCursor, endCursor *string
	if len(edges) > 0 {
		startCursor = &edges[0].Cursor
		endCursor = &edges[len(edges)-1].Cursor
	}

	return &model.CommentConnection{
		Edges: edges,
		PageInfo: &model.PageInfo{
			HasNextPage:     int64(int(offset)+len(comments)) < total,
			HasPreviousPage: offset > 0,
			StartCursor:     startCursor,
			EndCursor:       endCursor,
		},
		TotalCount: int(total),
	}, nil
}

// RelatedPlanets is the resolver for the relatedPlanets field.
func (r *queryResolver) RelatedPlanets(ctx context.Context, bodyID string, limit *int) ([]*model.RelationScore, error) {
	if r.useMock() {
		return mockRelatedPlanets(bodyID, limit)
	}

	// For now, return popular planets as related (semantic search not yet implemented)
	lim := 3
	if limit != nil {
		lim = *limit
	}
	bodies, err := r.Repos.Body.Popular(ctx, int32(lim+1))
	if err != nil {
		return nil, nil
	}

	var results []*model.RelationScore
	for i, b := range bodies {
		if b.ID.String() == bodyID {
			continue
		}
		results = append(results, &model.RelationScore{
			Planet: repository.BodyToGraphQLPlanet(&b),
			Score:  0.9 - float64(i)*0.1,
		})
		if len(results) >= lim {
			break
		}
	}
	return results, nil
}

