// FriendLinks is the resolver for the friendLinks field.
func (r *queryResolver) FriendLinks(ctx context.Context) ([]*model.FriendLink, error) {
	if r.useMock() {
		return mockFriendLinks, nil
	}

	if r.Cache != nil {
		var cached []*model.FriendLink
		if r.Cache.Get(ctx, cache.PrefixFriends, &cached) {
			return cached, nil
		}
	}

	links, err := r.Repos.FriendLink.ListActive(ctx)
	if err != nil {
		return nil, fmt.Errorf("list friend links: %w", err)
	}

	results := make([]*model.FriendLink, len(links))
	for i, fl := range links {
		results[i] = repository.FriendLinkToGraphQL(&fl)
	}

	if r.Cache != nil {
		r.Cache.Set(ctx, cache.PrefixFriends, results, cache.TTLFriends)
	}

	return results, nil
}

