func mockArchiveByYear(year int) (*model.ArchiveResult, error) {
	months := make([]*model.ArchiveMonth, 0)
	for m := 1; m <= 12; m++ {
		var ps []*model.Planet
		for _, p := range mockPlanets {
			if p.PublishedAt != nil && p.PublishedAt.Year() == year && int(p.PublishedAt.Month()) == m {
				ps = append(ps, p)
			}
		}
		if len(ps) > 0 {
			months = append(months, &model.ArchiveMonth{Month: m, Planets: ps, Count: len(ps)})
		}
	}
	total := 0
	for _, mo := range months {
		total += mo.Count
	}
	return &model.ArchiveResult{Year: year, Months: months, Total: total}, nil
}

func mockCommentConnection(bodySlug string) (*model.CommentConnection, error) {
	var matching []*model.Comment
	for _, c := range mockComments {
		if c.BodySlug == bodySlug {
			matching = append(matching, c)
		}
	}
	edges := make([]*model.CommentEdge, 0, len(matching))
	for _, c := range matching {
		edges = append(edges, &model.CommentEdge{Cursor: c.ID, Node: c})
	}
	var sc, ec *string
	if len(edges) > 0 {
		sc = &edges[0].Cursor
		ec = &edges[len(edges)-1].Cursor
	}
	return &model.CommentConnection{
		Edges: edges, PageInfo: &model.PageInfo{StartCursor: sc, EndCursor: ec}, TotalCount: len(matching),
	}, nil
}

func mockRelatedPlanets(bodyID string, limit *int) ([]*model.RelationScore, error) {
	lim := 3
	if limit != nil {
		lim = *limit
	}
	var results []*model.RelationScore
	for i, p := range mockPlanets {
		if p.ID == bodyID {
			continue
		}
		results = append(results, &model.RelationScore{Planet: p, Score: 0.9 - float64(i)*0.1})
		if len(results) >= lim {
			break
		}
	}
	return results, nil
}
